if MARKER in text:
    status = "already-applied"
else:
    anchor = "const MAPDATA = {"
    i = text.find(anchor)
    if i == -1:
        status = "ANCHOR-NOT-FOUND"
    else:
        start = text.find("{", i)
        depth = 0
        pos = start
        n = len(text)
        while pos < n:
            c = text[pos]
            if c == "{":
                depth += 1
            elif c == "}":
                depth -= 1
                if depth == 0:
                    break
            pos += 1
        end = pos + 1
        # safety check: the replacement JSON must itself be valid and carry
        # the same 242 features/iso3 codes as whatever is currently live,
        # so a stale/mismatched shipped patch can never silently drop data
        old_span = text[start:end]
        old_data = json.loads(old_span)
        new_data = json.loads(NEW_MAPDATA_JSON)
        old_iso3 = set(f["properties"].get("iso3") for f in old_data["features"])
        new_iso3 = set(f["properties"].get("iso3") for f in new_data["features"])
        if old_iso3 != new_iso3 or len(new_data["features"]) != len(old_data["features"]):
            status = "SAFETY-CHECK-FAILED (iso3/feature-count mismatch - not applying)"
        else:
            text = text[:i] + MARKER + "\nconst MAPDATA = " + NEW_MAPDATA_JSON + ";" + text[end + 1:]
            status = "patched"

open(OUT, "w", encoding="utf-8").write(text)
print(f"  [{status}] simplify MAPDATA geometry (tol=0.03deg, 4-decimal rounding, ~49% smaller)")
print("OK: MAPDATA simplified - fills/borders/glow should load far faster" if status in ("patched", "already-applied") else "WARN: review before deploying")
sys.exit(0 if status in ("patched", "already-applied") else 1)
